 58 TripletResult IR2VecTool::generateTriplets(const Function &F) const {
 59   if (F.isDeclaration())
 60     return {};
 61 
 62   TripletResult Result;
 63   Result.MaxRelation = 0;
 64 
 65   unsigned MaxRelation = NextRelation;
