657       Vocabulary::fromFile(VocabFile, OpcWeight, TypeWeight, ArgWeight);
658   if (!VocabOrErr) {
659     emitError(VocabOrErr.takeError(), *Ctx);
660     return Vocabulary();
661   }
662 
663   return std::move(*VocabOrErr);
